from django.shortcuts import render
from django.http import HttpResponse

# Create your views here.
def e39(request):
    return HttpResponse("The BMW E39 is the fourth generation of the BMW 5 Series range of executive cars, which was manufactured from 1996 to 2004. It was launched in the saloon body style, with the station wagon body style (marketed as Touring) introduced in 1996. The E39 was replaced by the E60 5 Series in 2003, however E39 models remained in production until May 2004. The proportion of chassis components using aluminium significantly increased for the E39, and it was the first 5 Series to use aluminium for all major components in the front suspension or any in the rear. It was also the first 5 Series where a four-cylinder diesel engine was available. Rack and pinion steering was used for four- and six-cylinder models, the first time that a 5 Series has used this steering system in significant volumes. Unlike its E34 predecessor and E60 successor, the E39 was not available with all-wheel drive. The high performance E39 M5 saloon was introduced in 1998; it was the first M5 model to be powered by a V8 engine.")

def m3(request):
    return HttpResponse("The BMW M3 is a high-performance version of the BMW 3 Series, developed by BMW's in-house motorsport division, BMW M GmbH. M3 models have been produced for every generation of 3 Series since the E30 M3 was introduced in 1986.The initial model was available in a coupé body style, with a convertible body style made available soon after. M3 saloons were offered initially during the E36 (1994–1999) and E90 (2008–2012) generations. Since 2014, the coupé and convertible models have been rebranded as the 4 Series range, making the high-performance variant the M4. Variants of the 3 Series since then have seen the M3 produced as a saloon, until 2020, when the M3 was produced as an estate (Touring) for the first time, alongside the saloon variant.")

def m8(request):
    return HttpResponse("The BMW M8 is the high-performance version of the BMW 8 Series (G15) marketed under the BMW M sub-brand.Introduced in June 2019, the M8 was initially produced in the 2-door convertible (F91 model code) and 2-door coupe (F92 model code) body styles.[4][5] A 4-door sedan (F93 model code, marketed as 'Gran Coupe') body style was added to the lineup in October 2019.[6][7][8][9] The M8 is powered by the BMW S63 twin-turbocharged V8 engine shared with the BMW M5 (F90).")

